/**
 * links add — Add a new link entry.
 *
 * Reads the nearest links.yaml, appends a new link, and writes it back
 * atomically. Validates the URL and rejects duplicate labels.
 */

import { findConfig, readConfig, writeConfig, validateUrl } from '../config.js';

export function registerAdd(program) {
  program
    .command('add <label> <url>')
    .description('Add a new link')
    .option('--icon <emoji>', 'Icon emoji or name for the link')
    .option('--description <text>', 'Short description of the link')
    .option('--from <date>', 'Scheduled start date (ISO 8601)')
    .option('--until <date>', 'Scheduled end date (ISO 8601)')
    .option('--update', 'Replace an existing link with the same label')
    .action(async (label, url, opts) => {
      // Validate URL
      const urlCheck = validateUrl(url);
      if (!urlCheck.valid) {
        console.error(`Error: ${urlCheck.error}`);
        process.exitCode = 1;
        return;
      }

      // Find and read config
      let configPath;
      let config;
      try {
        configPath = findConfig();
        config = readConfig(configPath);
      } catch (err) {
        console.error(`Error: ${err.message}`);
        process.exitCode = 1;
        return;
      }

      // Ensure links array exists
      if (!config.links) {
        config.links = [];
      }

      // Check for duplicate label (case-insensitive)
      const existingIndex = config.links.findIndex(
        (l) => l.label.toLowerCase() === label.toLowerCase(),
      );

      if (existingIndex !== -1 && !opts.update) {
        console.error(
          `A link with label "${label}" already exists. Use --update to replace it.`,
        );
        process.exitCode = 1;
        return;
      }

      // Build link object
      const link = { label, url };
      if (opts.icon) link.icon = opts.icon;
      if (opts.description) link.description = opts.description;
      if (opts.from) link.scheduled_from = opts.from;
      if (opts.until) link.scheduled_until = opts.until;

      // Add or replace
      if (existingIndex !== -1) {
        config.links[existingIndex] = link;
      } else {
        config.links.push(link);
      }

      // Write back
      try {
        writeConfig(configPath, config);
      } catch (err) {
        console.error(`Error: could not write links.yaml — ${err.message}`);
        process.exitCode = 1;
        return;
      }

      console.log(`✓ Added: ${label} → ${url}`);
    });
}

/**
 * links remove — Remove an existing link entry.
 *
 * Finds a link by label (case-insensitive), removes it from the config,
 * and writes the updated file atomically.
 */

import { findConfig, readConfig, writeConfig } from '../config.js';

export function registerRemove(program) {
  program
    .command('remove <label>')
    .description('Remove a link')
    .action(async (label) => {
      // Find and read config
      let configPath;
      let config;
      try {
        configPath = findConfig();
        config = readConfig(configPath);
      } catch (err) {
        console.error(`Error: ${err.message}`);
        process.exitCode = 1;
        return;
      }

      const links = config.links || [];

      // Find link by label (case-insensitive)
      const index = links.findIndex(
        (l) => l.label.toLowerCase() === label.toLowerCase(),
      );

      if (index === -1) {
        console.error(`No link with label "${label}" found.`);
        process.exitCode = 1;
        return;
      }

      // Remove the link
      const removed = links.splice(index, 1)[0];
      config.links = links;

      // Write back
      try {
        writeConfig(configPath, config);
      } catch (err) {
        console.error(`Error: could not write links.yaml — ${err.message}`);
        process.exitCode = 1;
        return;
      }

      console.log(`✓ Removed: ${removed.label}`);
    });
}

/**
 * links list — List all configured links.
 *
 * Reads the nearest links.yaml and prints a formatted table of links.
 * Supports --json for machine-readable output.
 */

import chalk from 'chalk';
import { findConfig, readConfig } from '../config.js';

/**
 * Build a schedule status string for a link.
 */
function scheduleStatus(link) {
  const parts = [];
  if (link.scheduled_from) parts.push(`from ${link.scheduled_from}`);
  if (link.scheduled_until) parts.push(`until ${link.scheduled_until}`);
  if (parts.length === 0) return '';
  return `🕐 ${parts.join(' ')}`;
}

/**
 * Pad a string to a given width.
 */
function pad(str, width) {
  const len = str.length;
  return len >= width ? str : str + ' '.repeat(width - len);
}

export function registerList(program) {
  program
    .command('list')
    .description('List all links')
    .option('--json', 'Output links as a JSON array')
    .action(async (opts) => {
      // Find and read config
      let config;
      try {
        const configPath = findConfig();
        config = readConfig(configPath);
      } catch (err) {
        console.error(`Error: ${err.message}`);
        process.exitCode = 1;
        return;
      }

      const links = config.links || [];

      if (links.length === 0) {
        console.log('No links yet. Use: links add <label> <url>');
        return;
      }

      // JSON output
      if (opts.json) {
        console.log(JSON.stringify(links, null, 2));
        return;
      }

      // Calculate column widths
      const idxWidth = String(links.length).length;
      let labelWidth = 5; // minimum "LABEL"
      let urlWidth = 3;   // minimum "URL"
      let iconWidth = 0;

      const hasIcons = links.some((l) => l.icon);

      for (const link of links) {
        if (link.label.length > labelWidth) labelWidth = link.label.length;
        if (link.url.length > urlWidth) urlWidth = link.url.length;
        if (link.icon && link.icon.length > iconWidth) iconWidth = link.icon.length;
      }

      // Print header
      let header = `${pad('#', idxWidth)}  ${pad('LABEL', labelWidth)}  ${pad('URL', urlWidth)}`;
      if (hasIcons) header += `  ${pad('ICON', iconWidth)}`;
      header += '  SCHEDULE';
      console.log(chalk.bold(header));
      console.log(chalk.gray('─'.repeat(header.length)));

      // Print rows
      links.forEach((link, i) => {
        const idx = pad(String(i + 1), idxWidth);
        const label = pad(link.label, labelWidth);
        const url = pad(link.url, urlWidth);
        const icon = hasIcons ? `  ${pad(link.icon || '', iconWidth)}` : '';
        const sched = scheduleStatus(link);

        let line = `${chalk.gray(idx)}  ${chalk.cyan(label)}  ${url}${icon}`;
        if (sched) line += `  ${chalk.yellow(sched)}`;
        console.log(line);
      });
    });
}
